const raw = $json.candidates[0].content.parts[0].text;

// remove markdown blocks if Gemini added them
const cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

// convert string → JSON
const agentSpec = JSON.parse(cleaned);

// ensure version exists
if (!agentSpec.version) {
  agentSpec.version = "v1";
}

return [
  {
    json: agentSpec
  }
];

const items = $input.all();

let memo = null;
let onboarding = null;

// Loop through Gemini responses
for (const item of items) {

  const raw = item.json.candidates[0].content.parts[0].text;

  // Remove ```json blocks if Gemini added them
  const cleaned = raw
    .replace(/```json/g, "")
    .replace(/```/g, "")
    .trim();

  const parsed = JSON.parse(cleaned);

  // Detect which file it came from
  if (!memo) {
    memo = parsed;
  } else {
    onboarding = parsed;
  }
}


// ---- MERGE LOGIC ----

// business hours
if (memo.business_hours.days === null && onboarding.business_hours?.days) {
  memo.business_hours = onboarding.business_hours;
}

// office address
if (!memo.office_address && onboarding.office_address) {
  memo.office_address = onboarding.office_address;
}

// emergency routing
if (memo.emergency_routing_rules.fallback === null && onboarding.emergency_routing_rules?.fallback) {
  memo.emergency_routing_rules = onboarding.emergency_routing_rules;
}

// call transfer rules
if (memo.call_transfer_rules.timeout === null && onboarding.call_transfer_rules?.timeout) {
  memo.call_transfer_rules = onboarding.call_transfer_rules;
}

// integration
if (!memo.integration_constraints && onboarding.integration_constraints) {
  memo.integration_constraints = onboarding.integration_constraints;
}


// return merged memo
return [
  {
    json: memo
  }
];

